#!/usr/bin/env node
import express from "express";
import cors from "cors";
import helmet from "helmet";
import { isRunAsPackage, projectRoot } from "./config.js";
import { registerRoutes } from "./routes.js";
import { startWatching } from "./fileWatch.js";

const app = express();
app.use(helmet());
app.use(cors({ origin: /^https?:\/\/localhost(:\d+)?$/ }));
registerRoutes(app);

const rawPort = process.env.PORT || "3000";
if (process.env.PORT && !/^\d+$/.test(rawPort)) {
  console.error(`Invalid PORT value: ${rawPort}`);
  process.exit(1);
}
const PORT = parseInt(rawPort, 10);
if (isNaN(PORT) || PORT < 1 || PORT > 65535) {
  console.error(`Invalid PORT value: ${rawPort}`);
  process.exit(1);
}

app.listen(PORT, () => {
  const url = `http://localhost:${PORT}`;
  console.log(`BMAD dashboard at ${url}`);
  if (isRunAsPackage) console.log(`Project root: ${projectRoot}`);
  startWatching(projectRoot);
});
